{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d bookreview_db -c \"SELECT column_name, data_type FROM information_schema.columns WHERE table_name='books_info';\"",
  "description": "Inspect books_info schema"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d bookreview_db -c \"SELECT categories FROM books_info WHERE categories ILIKE '%Literature%' LIMIT 5;\"",
  "description": "Sample categories format"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d bookreview_db -c \"SELECT details FROM books_info WHERE details ILIKE '%English%' LIMIT 3;\"",
  "description": "Sample details with English language"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d bookreview_db -c \"SELECT COUNT(*) FROM books_info WHERE categories ILIKE '%Literature & Fiction%' AND (details ILIKE '%in English%' OR details ILIKE '%written in English%' OR details ILIKE '%available in English%');\"",
  "description": "Count English literature books"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d bookreview_db -c \"COPY (SELECT book_id, title FROM books_info WHERE categories ILIKE '%Literature & Fiction%' AND (details ILIKE '%in English%' OR details ILIKE '%written in English%' OR details ILIKE '%available in English%')) TO STDOUT WITH CSV HEADER;\" > /tmp/eng_lit_books.csv\nwc -l /tmp/eng_lit_books.csv",
  "description": "Export English Lit & Fiction books"
}

{
  "command": "sqlite3 '/Users/shreyashankar/Documents/projects/DataAgentBench/query_bookreview/query_dataset/review_query.db' \"SELECT purchase_id, rating FROM review LIMIT 5;\"\npsql -h 127.0.0.1 -U shreyashankar -d bookreview_db -c \"SELECT book_id FROM books_info LIMIT 5;\"",
  "description": "Check format of IDs"
}

{
  "command": "sqlite3 '/Users/shreyashankar/Documents/projects/DataAgentBench/query_bookreview/query_dataset/review_query.db' \"SELECT COUNT(DISTINCT purchase_id), MIN(CAST(SUBSTR(purchase_id, 12) AS INTEGER)), MAX(CAST(SUBSTR(purchase_id, 12) AS INTEGER)) FROM review;\"\npsql -h 127.0.0.1 -U shreyashankar -d bookreview_db -c \"SELECT COUNT(*), MIN(CAST(SUBSTR(book_id, 8) AS INTEGER)), MAX(CAST(SUBSTR(book_id, 8) AS INTEGER)) FROM books_info;\"",
  "description": "Check ID ranges"
}
